      Promise.race([
        speakWithBrowserTTS(goodbyeText),
        new Promise(resolve => setTimeout(resolve, 3000))
      ]).catch(() => {})
    }

    try {
      // Send frames for body language analysis
      const frames = mockFramesRef.current.length > 0 ? mockFramesRef.current : undefined
