                          <p className="text-xs text-emerald-700">{coaching.presentation.summary}</p>
                        </div>
                      )}

                      {/* Timestamped notes */}
                      {coaching.presentation.timestamped_notes && coaching.presentation.timestamped_notes.length > 0 && (
